   161→const WarningAnnouncementModal = React.memo(({ isVisible, onClose, currentUserProfile, currentRoomId }) => {
   162→  const [type, setType]               = useState('warning');
   163→  const [title, setTitle]             = useState('');
   164→  const [message, setMessage]         = useState('');
