   171→  const [allowDismiss, setAllowDismiss] = useState(true);
   172→  const [iconType, setIconType]       = useState('warning');
   173→  const [rooms, setRooms]             = useState([]);
   174→  const [users, setUsers]             = useState([]);
   175→  const [isLoading, setIsLoading]     = useState(false);
   176→  const [userSearch, setUserSearch]   = useState('');
   177→  const [searchResults, setSearchResults] = useState(null);
   178→  const [isSearching, setIsSearching] = useState(false);
   179→
   180→  useEffect(() => {
   181→    if (!isVisible) return;
   182→    const cacheIsFresh = _cachedModalData && (Date.now() - _cachedModalData.fetchedAt) < MODAL_CACHE_TTL_MS;
   183→    if (cacheIsFresh) {
   184→      setRooms(_cachedModalData.rooms);
   185→      setUsers(_cachedModalData.users);
   186→      if (currentRoomId && !selectedRooms.includes(currentRoomId)) setSelectedRooms([currentRoomId]);
   187→      return;
   188→    }
   189→    const unsubRooms = onSnapshot(query(collection(db, 'rooms'), orderBy('name')), (snap) => {
   190→      const roomsData = snap.docs.map(d => ({ id: d.id, ...d.data() }));
   191→      setRooms(roomsData);
   192→      if (currentRoomId && !selectedRooms.includes(currentRoomId)) setSelectedRooms([currentRoomId]);
   193→      _cachedModalData = { ..._cachedModalData, rooms: roomsData, users: _cachedModalData?.users || [], fetchedAt: Date.now() };
   194→    });
   195→    const unsubUsers = onSnapshot(query(collection(db, 'users'), limit(100)), (snap) => {
   196→      const usersData = snap.docs.map(d => ({ id: d.id, ...d.data() }));
   197→      setUsers(usersData);
   198→      _cachedModalData = { ..._cachedModalData, users: usersData, rooms: _cachedModalData?.rooms || [], fetchedAt: Date.now() };
   199→    });
   200→    return () => { unsubRooms(); unsubUsers(); };
   201→  }, [isVisible, currentRoomId]);
   202→
   203→  useEffect(() => {
   204→    if (!isVisible || targetType !== 'selected_users') return;
   205→    const term = userSearch.trim();
   206→    if (!term) { setSearchResults(null); return; }
   207→    let cancelled = false;
   208→    setIsSearching(true);
   209→    const handle = setTimeout(async () => {
   210→      try {
   211→        const q1 = query(collection(db, 'users'), orderBy('displayName'),
   212→          where('displayName', '>=', term), where('displayName', '<=', term + '\uf8ff'), limit(30));
   213→        const snap = await getDocs(q1);
   214→        if (!cancelled) setSearchResults(snap.docs.map(d => ({ id: d.id, ...d.data() })));
   215→      } catch (err) {
   216→        if (!cancelled) setSearchResults(null);
   217→      } finally {
   218→        if (!cancelled) setIsSearching(false);
   219→      }
   220→    }, 300);
   221→    return () => { cancelled = true; clearTimeout(handle); };
   222→  }, [userSearch, isVisible, targetType]);
   223→
   224→  const getBgBorder = () => {
   225→    if (type === 'warning') {
   226→      const m = { low: ['#fffbeb','#f59e0b'], medium: ['#fff7ed','#ef4444'], high: ['#fff1f2','#dc2626'], critical: ['#fff1f2','#991b1b'] };
   227→      return m[severity] || m.medium;
   228→    }
   229→    return ['#faf5ff', '#7c3aed'];
   230→  };
   231→  const [cardBg, accentC] = getBgBorder();
   232→  const isWarning = type === 'warning';
   233→
   234→  const handleSubmit = async () => {
   235→    if (!title.trim() || !message.trim()) return;
   236→    if (targetType === 'selected_rooms' && selectedRooms.length === 0) return;
   237→    if (targetType === 'selected_users' && selectedUsers.length === 0) return;
